    49→/* An implementation of Envoy::ConnectionPool::ConnPoolImplBase for shared code
    50→ * between HTTP/1.1 and HTTP/2
    51→ *
    52→ * NOTE: The connection pool does NOT do DNS resolution. It assumes it is being given a numeric IP
    53→ *       address. Higher layer code should handle resolving DNS on error and creating a new pool
    54→ *       bound to a different IP address.
    55→ */
    56→class HttpConnPoolImplBase : public Envoy::ConnectionPool::ConnPoolImplBase,
    57→                             public Http::ConnectionPool::Instance {
    58→public:
    59→  HttpConnPoolImplBase(
    60→      Upstream::HostConstSharedPtr host, Upstream::ResourcePriority priority,
    61→      Event::Dispatcher& dispatcher, const Network::ConnectionSocket::OptionsSharedPtr& options,
    62→      const Network::TransportSocketOptionsConstSharedPtr& transport_socket_options,
    63→      Random::RandomGenerator& random_generator, Upstream::ClusterConnectivityState& state,
    64→      std::vector<Http::Protocol> protocols, Server::OverloadManager& overload_manager);
    65→  ~HttpConnPoolImplBase() override;
    66→
    67→  // Event::DeferredDeletable
    68→  void deleteIsPending() override { deleteIsPendingImpl(); }
    69→
    70→  // ConnectionPool::Instance
    71→  void addIdleCallback(IdleCb cb) override { addIdleCallbackImpl(cb); }
    72→  bool isIdle() const override { return isIdleImpl(); }
    73→  void drainConnections(Envoy::ConnectionPool::DrainBehavior drain_behavior) override {
    74→    drainConnectionsImpl(drain_behavior);
    75→  }
    76→  Upstream::HostDescriptionConstSharedPtr host() const override { return host_; }
    77→  ConnectionPool::Cancellable* newStream(Http::ResponseDecoder& response_decoder,
    78→                                         Http::ConnectionPool::Callbacks& callbacks,
    79→                                         const Instance::StreamOptions& options) override;
    80→  bool maybePreconnect(float ratio) override { return maybePreconnectImpl(ratio); }
    81→  bool hasActiveConnections() const override;
    82→
    83→  // Creates a new PendingStream and enqueues it into the queue.
    84→  ConnectionPool::Cancellable* newPendingStream(Envoy::ConnectionPool::AttachContext& context,
    85→                                                bool can_send_early_data) override;
    86→  void onPoolFailure(const Upstream::HostDescriptionConstSharedPtr& host_description,
    87→                     absl::string_view failure_reason, ConnectionPool::PoolFailureReason reason,
    88→                     Envoy::ConnectionPool::AttachContext& context) override {
    89→    auto* callbacks = typedContext<HttpAttachContext>(context).callbacks_;
    90→    callbacks->onPoolFailure(reason, failure_reason, host_description);
    91→  }
    92→  void onPoolReady(Envoy::ConnectionPool::ActiveClient& client,
    93→                   Envoy::ConnectionPool::AttachContext& context) override;
    94→
    95→  virtual CodecClientPtr createCodecClient(Upstream::Host::CreateConnectionData& data) PURE;
    96→  Random::RandomGenerator& randomGenerator() { return random_generator_; }
    97→
    98→  virtual absl::optional<HttpServerPropertiesCache::Origin>& origin() { return origin_; }
    99→  virtual Http::HttpServerPropertiesCacheSharedPtr cache() { return nullptr; }
   100→
   101→protected:
   102→  friend class ActiveClient;
   103→
   104→  void setOrigin(absl::optional<HttpServerPropertiesCache::Origin> origin) { origin_ = origin; }
   105→
   106→  Random::RandomGenerator& random_generator_;
   107→
   108→private:
   109→  absl::optional<HttpServerPropertiesCache::Origin> origin_;
   110→};
