    49→    std::vector<Http::Protocol> protocols, Server::OverloadManager& overload_manager)
    50→    : Envoy::ConnectionPool::ConnPoolImplBase(
    51→          host, priority, dispatcher, options,
    52→          wrapTransportSocketOptions(transport_socket_options, protocols), state, overload_manager),
    53→      random_generator_(random_generator) {
    54→  ASSERT(!protocols.empty());
