    74→  Http::ResponseDecoder& decoder = *typedContext<HttpAttachContext>(context).decoder_;
    75→  Http::ConnectionPool::Callbacks& callbacks = *typedContext<HttpAttachContext>(context).callbacks_;
    76→  ENVOY_LOG(debug,
    77→            "queueing stream due to no available connections (ready={} busy={} connecting={})",
    78→            ready_clients_.size(), busy_clients_.size(), connecting_clients_.size());
    79→  Envoy::ConnectionPool::PendingStreamPtr pending_stream(
    80→      new HttpPendingStream(*this, decoder, callbacks, can_send_early_data));
    81→  return addPendingStream(std::move(pending_stream));
