   111→void MultiplexedActiveClientBase::onGoAway(Http::GoAwayErrorCode) {
   112→  ENVOY_CONN_LOG(debug, "remote goaway", *codec_client_);
   113→  parent_.host()->cluster().trafficStats()->upstream_cx_close_notify_.inc();
   114→  if (state() != ActiveClient::State::Draining) {
   115→    if (codec_client_->numActiveRequests() == 0) {
   116→      codec_client_->close();
   117→    } else {
   118→      parent_.transitionActiveClientState(*this, ActiveClient::State::Draining);
   119→    }
   120→  }
   121→}
   122→
   123→// Adjust the concurrent stream limit if the negotiated concurrent stream limit
   124→// is lower than the local max configured streams.
   125→//
   126→// Note: if multiple streams are assigned to a connection before the settings
   127→// are received, they may still be reset by the peer. This could be avoided by
   128→// not considering http/2 connections connected until the SETTINGS frame is
   129→// received, but that would result in a latency penalty instead.
   130→void MultiplexedActiveClientBase::onSettings(ReceivedSettings& settings) {
   131→  if (settings.maxConcurrentStreams().has_value()) {
   132→    int64_t old_unused_capacity = currentUnusedCapacity();
   133→    // Given config limits old_unused_capacity should never exceed int32_t.
   134→    ASSERT(std::numeric_limits<int32_t>::max() >= old_unused_capacity);
   135→    if (parent().cache() && parent().origin().has_value()) {
   136→      parent().cache()->setConcurrentStreams(*parent().origin(),
   137→                                             settings.maxConcurrentStreams().value());
   138→    }
   139→    concurrent_stream_limit_ =
   140→        std::min(settings.maxConcurrentStreams().value(), configured_stream_limit_);
   141→
   142→    int64_t delta = old_unused_capacity - currentUnusedCapacity();
   143→    if (state() == ActiveClient::State::Ready && currentUnusedCapacity() <= 0) {
