    92→bool ConnPoolImplBase::shouldConnect(size_t pending_streams, size_t active_streams,
    93→                                     int64_t connecting_and_connected_capacity,
    94→                                     float preconnect_ratio, bool anticipate_incoming_stream) {
    95→  // This is set to true any time global preconnect is being calculated.
    96→  // ClusterManagerImpl::maybePreconnect is called directly before a stream is created, so the
    97→  // stream must be anticipated.
    98→  //
    99→  // Also without this, we would never pre-establish a connection as the first
   100→  // connection in a pool because pending/active streams could both be 0.
   101→  int anticipated_streams = anticipate_incoming_stream ? 1 : 0;
   102→
   103→  // The number of streams we want to be provisioned for is the number of
   104→  // pending, active, and anticipated streams times the preconnect ratio.
   105→  // The number of streams we are (theoretically) provisioned for is the
   106→  // connecting stream capacity plus the number of active streams.
   107→  //
   108→  // If preconnect ratio is not set, it defaults to 1, and this simplifies to the
   109→  // legacy value of pending_streams_.size() > connecting_stream_capacity_
   110→  return (pending_streams + active_streams + anticipated_streams) * preconnect_ratio >
   111→         connecting_and_connected_capacity + active_streams;
   112→}
