   114→bool ConnPoolImplBase::shouldCreateNewConnection(float global_preconnect_ratio) const {
   115→  // If the host is not healthy, don't make it do extra work, especially as
   116→  // upstream selection logic may result in bypassing this upstream entirely.
   117→  // If an Envoy user wants preconnecting for degraded upstreams this could be
   118→  // added later via extending the preconnect config.
   119→  if (host_->coarseHealth() != Upstream::Host::Health::Healthy) {
   120→    return pending_streams_.size() > connecting_stream_capacity_;
   121→  }
   122→
   123→  // Determine if we are trying to prefetch for global preconnect or local preconnect.
   124→  if (global_preconnect_ratio != 0) {
   125→    // If global preconnecting is on, and this connection is within the global
   126→    // preconnect limit, preconnect.
   127→    // For global preconnect, we anticipate an incoming stream to this pool, since it is
   128→    // prefetching for the next upcoming stream, which will likely be assigned to this pool.
   129→    // We may eventually want to track preconnect_attempts to allow more preconnecting for
   130→    // heavily weighted upstreams or sticky picks.
   131→    bool result =
   132→        shouldConnect(pending_streams_.size(), num_active_streams_,
   133→                      connecting_and_connected_stream_capacity_, global_preconnect_ratio, true);
   134→    ENVOY_LOG(trace,
   135→              "predictive shouldCreateNewConnection returns {} for pending {} active {} "
   136→              "connecting_and_connected_capacity {} connecting_capacity {} ratio {}",
   137→              result, pending_streams_.size(), num_active_streams_,
   138→              connecting_and_connected_stream_capacity_, connecting_stream_capacity_,
   139→              global_preconnect_ratio);
   140→    return result;
   141→  } else {
   142→    // Ensure this local pool has adequate connections for the given load.
   143→    //
   144→    // Local preconnect does not need to anticipate a stream. It is called as
   145→    // new streams are established or torn down and simply attempts to maintain
   146→    // the correct ratio of streams and anticipated capacity.
   147→    bool result =
   148→        shouldConnect(pending_streams_.size(), num_active_streams_,
   149→                      connecting_and_connected_stream_capacity_, perUpstreamPreconnectRatio());
   150→    ENVOY_LOG(trace,
   151→              "per-upstream shouldCreateNewConnection returns {} for pending {} active {} "
   152→              "connecting_and_connected_capacity {} connecting_capacity {} ratio {}",
   153→              result, pending_streams_.size(), num_active_streams_,
   154→              connecting_and_connected_stream_capacity_, connecting_stream_capacity_,
   155→              perUpstreamPreconnectRatio());
   156→    return result;
   157→  }
   158→}
