   164→ConnPoolImplBase::ConnectionResult ConnPoolImplBase::tryCreateNewConnections() {
   165→  ConnPoolImplBase::ConnectionResult result;
   166→  // Somewhat arbitrarily cap the number of connections preconnected due to new
   167→  // incoming connections. The preconnect ratio is capped at 3, so in steady
   168→  // state, no more than 3 connections should be preconnected. If hosts go
   169→  // unhealthy, and connections are not immediately preconnected, it could be that
   170→  // many connections are desired when the host becomes healthy again, but
   171→  // overwhelming it with connections is not desirable.
   172→  for (int i = 0; i < 3; ++i) {
   173→    result = tryCreateNewConnection();
   174→    if (result != ConnectionResult::CreatedNewConnection) {
   175→      break;
   176→    }
   177→  }
   178→  ASSERT(!is_draining_for_deletion_ || result != ConnectionResult::CreatedNewConnection,
   179→         dumpState());
   180→  return result;
   181→}
