   183→ConnPoolImplBase::ConnectionResult
   184→ConnPoolImplBase::tryCreateNewConnection(float global_preconnect_ratio) {
   185→  // There are already enough Connecting connections for the number of queued streams.
   186→  if (!shouldCreateNewConnection(global_preconnect_ratio)) {
   187→    return ConnectionResult::ShouldNotConnect;
   188→  }
   189→  ENVOY_LOG(trace, "creating new preconnect connection");
   190→
   191→  // Drop new connection attempts if the load shed point indicates overload.
   192→  if (create_new_connection_load_shed_) {
   193→    if (create_new_connection_load_shed_->shouldShedLoad()) {
   194→      return ConnectionResult::LoadShed;
   195→    }
   196→  }
   197→
   198→  const bool can_create_connection = host_->canCreateConnection(priority_);
   199→
   200→  if (!can_create_connection) {
   201→    host_->cluster().trafficStats()->upstream_cx_overflow_.inc();
   202→  }
   203→  // If we are at the connection circuit-breaker limit due to other upstreams having
   204→  // too many open connections, and this upstream has no connections, always create one, to
   205→  // prevent pending streams being queued to this upstream with no way to be processed.
   206→  if (can_create_connection || (ready_clients_.empty() && busy_clients_.empty() &&
   207→                                connecting_clients_.empty() && early_data_clients_.empty())) {
   208→    ENVOY_LOG(debug, "creating a new connection (connecting={})", connecting_clients_.size());
   209→    ActiveClientPtr client = instantiateActiveClient();
   210→    if (client.get() == nullptr) {
   211→      ENVOY_LOG(trace, "connection creation failed");
   212→      return ConnectionResult::FailedToCreateConnection;
   213→    }
   214→    ASSERT(client->state() == ActiveClient::State::Connecting, dumpState());
   215→    ENVOY_BUG(std::numeric_limits<uint64_t>::max() - connecting_stream_capacity_ >=
   216→                  static_cast<uint64_t>(client->currentUnusedCapacity()),
   217→              dumpState());
   218→    ASSERT(client->real_host_description_);
