   224→                                 : ConnectionResult::CreatedButRateLimited;
   225→  } else {
   226→    ENVOY_LOG(trace, "not creating a new connection: connection constrained");
   227→    return ConnectionResult::NoConnectionRateLimited;
   228→  }
