    ENVOY_CONN_LOG(debug, "maximum streams per connection, start draining", client);
    traffic_stats.upstream_cx_max_requests_.inc();
    transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Draining);
