  host_->stats().rq_active_.inc();
  traffic_stats.upstream_rq_total_.inc();
  traffic_stats.upstream_rq_active_.inc();
  host_->cluster().resourceManager(priority_).requests().inc();

  onPoolReady(client, context);
}

