   139→/**
   140→ * Base implementation of most of Upstream::HostDescription, shared between
   141→ * HostDescriptionImpl and LogicalHost, which is in
   142→ * source/extensions/clusters/common/logical_host.h. These differ in threading.
   143→ *
   144→ * HostDescriptionImpl and HostImpl are intended to be initialized in the main
   145→ * thread, and are thereafter read-only, and thus do not require locking.
   146→ *
   147→ * LogicalHostImpl is intended to be dynamically changed due to DNS resolution
   148→ * and Happy Eyeballs from multiple threads, and thus requires an address_lock
   149→ * and lock annotations to enforce this.
   150→ *
   151→ * The two level implementation inheritance allows most of the implementation
   152→ * to be shared, but sinks the ones requiring different lock semantics into
   153→ * the leaf subclasses.
   154→ */
   155→class HostDescriptionImplBase : virtual public HostDescription,
   156→                                protected Logger::Loggable<Logger::Id::upstream> {
   157→public:
   158→  Network::UpstreamTransportSocketFactory& transportSocketFactory() const override {
   159→    absl::ReaderMutexLock lock(&metadata_mutex_);
   160→    return socket_factory_;
   161→  }
   162→
   163→  bool canary() const override { return canary_; }
   164→  void canary(bool is_canary) override { canary_ = is_canary; }
   165→
   166→  // Metadata getter/setter.
   167→  //
   168→  // It's possible that the lock that guards the metadata will become highly contended (e.g.:
   169→  // endpoints churning during a deploy of a large cluster). A possible improvement
   170→  // would be to use TLS and post metadata updates from the main thread. This model would
   171→  // possibly benefit other related and expensive computations too (e.g.: updating subsets).
   172→  MetadataConstSharedPtr metadata() const override {
   173→    absl::ReaderMutexLock lock(&metadata_mutex_);
   174→    return endpoint_metadata_;
   175→  }
   176→  void metadata(MetadataConstSharedPtr new_metadata) override {
   177→    auto& new_socket_factory = resolveTransportSocketFactory(address(), new_metadata.get());
   178→    {
   179→      absl::WriterMutexLock lock(&metadata_mutex_);
   180→      endpoint_metadata_ = new_metadata;
   181→      // Update data members dependent on metadata.
   182→      socket_factory_ = new_socket_factory;
   183→    }
   184→  }
   185→
   186→  const ClusterInfo& cluster() const override { return *cluster_; }
   187→  HealthCheckHostMonitor& healthChecker() const override {
   188→    if (health_checker_) {
   189→      return *health_checker_;
   190→    }
   191→
   192→    static HealthCheckHostMonitorNullImpl* null_health_checker =
   193→        new HealthCheckHostMonitorNullImpl();
   194→    return *null_health_checker;
   195→  }
   196→
   197→  bool canCreateConnection(Upstream::ResourcePriority priority) const override {
   198→    if (stats().cx_active_.value() >= cluster().resourceManager(priority).maxConnectionsPerHost()) {
   199→      return false;
   200→    }

